# Dependency to get DB session
def get_db():
    db = SessionLocal()
    try:
        yield db
    finally:
        db.close()

# --- 2. GraphQL Schema (Strawberry) ---

@strawberry.type
class SellerType:
    id: int
    name: str
    location: str

@strawberry.type
class CategoryType:
    id: int
    name: str
    description: str

@strawberry.type
class ImageType:
    id: int
    url: str
    alt_text: str

@strawberry.type
class ReviewType:
    id: int
    rating: int
    comment: str

@strawberry.type
class ProductType:
    id: int
    name: str
    description: str
    price: float

    @strawberry.field
    def seller(self, info: strawberry.Info) -> SellerType:
        # info.context["db"] is the SQLAlchemy session
        return info.context["db"].query(Seller).filter(Seller.id == self.seller_id).first()

    @strawberry.field
    def category(self, info: strawberry.Info) -> CategoryType:
        return info.context["db"].query(Category).filter(Category.id == self.category_id).first()

    @strawberry.field
    def reviews(self, info: strawberry.Info) -> List[ReviewType]:
        return info.context["db"].query(Review).filter(Review.product_id == self.id).all()

    @strawberry.field
    def images(self, info: strawberry.Info) -> List[ImageType]:
        return info.context["db"].query(Image).filter(Image.product_id == self.id).all()


@strawberry.type
class Query:
    @strawberry.field
    def products(self, info: strawberry.Info, search: Optional[str] = None) -> List[ProductType]:
        db: Session = info.context["db"]
        query = db.query(Product)
        if search:
            query = query.filter(
                (Product.name.contains(search)) |
                (Product.description.contains(search))
            )
        return query.all()

    @strawberry.field
    def product(self, info: strawberry.Info, id: int) -> Optional[ProductType]:
        db: Session = info.context["db"]
        return db.query(Product).filter(Product.id == id).first()

# Define the GraphQL schema
schema = strawberry.Schema(query=Query)

# --- 3. Application (Starlette/ASGI) ---

class CustomGraphQL(GraphQL):
    async def get_context(self, request, response) -> dict:
        # Inject the database session into the context for resolvers
        db_generator = get_db()
        db = next(db_generator) # Get the session
        return {"db": db, "request": request, "response": response}

    async def process_result(self, request, result, *args, **kwargs):
        # Close the database session after processing the request
        if "db" in request.scope["strawberry.context"]:
            db = request.scope["strawberry.context"]["db"]
            if db:
                db.close()
        return await super().process_result(request, result, *args, **kwargs)

graphql_app = CustomGraphQL(schema)

routes = [
    Route("/graphql", graphql_app),
]

app = Starlette(routes=routes)

